SELECT ts,
       value_number AS valueNumber
FROM device_telemetry
WHERE tenant_id = #{tenantId}
  AND device_id = #{deviceId}
  AND property = #{property}
  AND value_number IS NOT NULL
ORDER BY ts DESC
LIMIT #{limit}

SELECT code
FROM alarm_recipient_groups
WHERE tenant_id = #{tenantId}
  AND code IN

    #{code}

ORDER BY code ASC

SELECT id AS userId, username, real_name AS realName, phone, email FROM users WHERE tenant_id = #{tenantId} AND username IN
#{username}
AND status = 'ACTIVE' AND deleted_at IS NULL ORDER BY username ASC

SELECT DISTINCT u.id AS userId, u.username, u.real_name AS realName, u.phone, u.email FROM alarm_recipient_groups g JOIN alarm_recipient_group_members gm ON gm.tenant_id = g.tenant_id AND gm.group_id = g.id JOIN users u ON u.id = gm.user_id AND u.tenant_id = g.tenant_id WHERE g.tenant_id = #{tenantId} AND g.code IN
#{code}
AND u.status = 'ACTIVE' AND u.deleted_at IS NULL ORDER BY u.username ASC

SELECT id, tenant_id AS tenantId, type, name FROM notification_channels WHERE enabled = TRUE AND type IN
#{type}
AND ( tenant_id = #{tenantId} OR ( tenant_id = 0 AND #{tenantId} IS NOT NULL AND #{tenantId} <> 0 AND type <> 'WEBHOOK' ) ) ORDER BY type ASC, CASE WHEN tenant_id = #{tenantId} THEN 0 ELSE 1 END ASC, id ASC
